Example 1: MFE pub/sub across remote and hostRequest-Reply
Git: https://github.com/shaurcasm/nirnam/tree/main/Examples/transport
Host app ← → Cart remote app: This example showcases how apps can request information/state/data from each other and reply.
// Requester
// src/components/HostPanel.tsx lines 27–39
const getTotal = useCallback(async () => {
setBusy("total");
setResult(null);
log({ service: "Host", color: "#1d4ed8", kind: "req", topic: "cart:getTotal", data: "" });
try {
const total = await bus.request<void, number>("cart:getTotal", undefined, 3000); // types generics, explicit timeout, await
setResult(`Cart total: $${total}`);
log({ service: "Host", color: "#1d4ed8", kind: "res", topic: "cart:getTotal", data: `$${total}` });
} catch (e) {
setResult(`Error: ${(e as Error).message}`);
}
setBusy("");
}, [log]);// Handler
// src/components/CartPanel.tsx lines 31–35
const unsubTotal = bus.handle<void, number>("cart:getTotal", () => {
const t = totalRef.current;
log({ service: "Cart", color: "#15803d", kind: "res", topic: "cart:getTotal", data: `$${t}` });
return t;
}); // synchronous handler returning a value; Nirnam wraps the Promise automatically
// With payload
// HostPanel.tsx lines 41–55
const checkout = useCallback(async () => {
setBusy("checkout");
setResult(null);
log({ service: "Host", color: "#1d4ed8", kind: "req", topic: "cart:checkout", data: '{ note: "rush" }' });
try {
const r = await bus.request<{ note: string }, { orderId: string; total: number }>(
"cart:checkout", { note: "rush" }, 3000,
);
setResult(`Order placed: ${r.orderId} ($${r.total})`);
log({ service: "Host", color: "#1d4ed8", kind: "res", topic: "cart:checkout", data: JSON.stringify(r) });
} catch (e) {
setResult(`Error: ${(e as Error).message}`);
}
setBusy("");
}, [log]);
// CartPanel.tsx lines 37–49
const unsubCheckout = bus.handle<{ note?: string }, { orderId: string; total: number }>(
"cart:checkout",
(payload) => {
const orderId = `ORD-${Date.now().toString(36).toUpperCase()}`;
const t = totalRef.current;
log({ service: "Cart", color: "#15803d", kind: "res", topic: "cart:checkout", data: orderId });
bus.publish("order:placed", { orderId, items: itemsRef.current, total: t, note: payload?.note });
log({ service: "Cart", color: "#15803d", kind: "pub", topic: "order:placed", data: JSON.stringify({ orderId, total: t }) });
setItems(INITIAL_ITEMS);
setOrderCount(c => c + 1);
return { orderId, total: t };
},
);
The generic types for the payload are enforced end-to-end. The handler never sees the request ID or the correlation machinery — it just returns a value. Simple communication. सरल सञ्चारः
