Example 2: Three independent createBus instances requesting/recieving dataStreaming
Git: https://github.com/shaurcasm/nirnam/tree/main/Examples/transport
Streaming our Host <> Cart example for a bit more…
// Stream requester
// src/components/HostPanel.tsx lines 62–75
const streamPrices = useCallback(async () => {
setPrices([]);
setBusy("stream");
log({ service: "Host", color: "#1d4ed8", kind: "stream", topic: "cart:priceStream", data: "starting…" });
try {
for await (const chunk of bus.requestStream<void, string>("cart:priceStream", undefined)) {
setPrices(p => [...p, chunk]);
log({ service: "Host", color: "#1d4ed8", kind: "stream", topic: "cart:priceStream", data: chunk });
}
} catch (e) {
log({ service: "Host", color: "#1d4ed8", kind: "stream", topic: "cart:priceStream", data: `ERROR: ${(e as Error).message}` });
}
setBusy("");
}, [log]);// Stream handler
// src/components/CartPanel.tsx lines 52–59
const unsubStream = bus.handleStream<void, string>("cart:priceStream", async function* () {
for (const item of itemsRef.current) {
const chunk = `${item.name}: $${item.price}`;
log({ service: "Cart", color: "#15803d", kind: "stream", topic: "cart:priceStream", data: chunk });
yield chunk;
await new Promise(r => setTimeout(r, 400));
}
});
